import{a as e,c as t,i as n,l as r,n as i,o as a,r as o,s,t as c}from"./app-B1jqjtqq.js";var l=JSON.parse(`{"path":"/go-tutor/framework/gorm/","title":"GORM 教程：从入门到实践","lang":"zh-CN","frontmatter":{"description":"GORM 教程：从入门到实践 GORM 是 Go 生态中最流行的 ORM（对象关系映射）库。它帮我们把数据库表映射成 Go 结构体，让我们能用操作结构体的方式操作数据库，不用手写 SQL。 为什么要用 ORM？ 直接写 SQL 本身没什么问题，但在实际项目中会遇到几个痛点： 重复劳动：每个表都要写增删改查，代码大量重复 类型不安全：SQL 字符串拼错一...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"GORM 教程：从入门到实践\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-15T15:17:39.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/go-tutor/framework/gorm/"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"GORM 教程：从入门到实践"}],["meta",{"property":"og:description","content":"GORM 教程：从入门到实践 GORM 是 Go 生态中最流行的 ORM（对象关系映射）库。它帮我们把数据库表映射成 Go 结构体，让我们能用操作结构体的方式操作数据库，不用手写 SQL。 为什么要用 ORM？ 直接写 SQL 本身没什么问题，但在实际项目中会遇到几个痛点： 重复劳动：每个表都要写增删改查，代码大量重复 类型不安全：SQL 字符串拼错一..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-15T15:17:39.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-15T15:17:39.000Z"}]]},"git":{"createdTime":1656256324000,"updatedTime":1784128659000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":3,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":6.8,"words":2041},"filePathRelative":"go-tutor/framework/gorm/README.md","autoDesc":true}`),u={name:`README.md`};function d(c,l,u,d,f,p){let m=t(`Catalog`),h=t(`RouteLink`);return s(),o(`div`,null,[l[5]||=i(`h1`,{id:`gorm-教程-从入门到实践`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#gorm-教程-从入门到实践`},[i(`span`,null,`GORM 教程：从入门到实践`)])],-1),a(m),l[6]||=n(`<p><a href="https://gorm.io/" target="_blank" rel="noopener noreferrer">GORM</a> 是 Go 生态中最流行的 ORM（对象关系映射）库。它帮我们把数据库表映射成 Go 结构体，让我们能用操作结构体的方式操作数据库，不用手写 SQL。</p><h2 id="为什么要用-orm" tabindex="-1"><a class="header-anchor" href="#为什么要用-orm"><span>为什么要用 ORM？</span></a></h2><p>直接写 SQL 本身没什么问题，但在实际项目中会遇到几个痛点：</p><ul><li><strong>重复劳动</strong>：每个表都要写增删改查，代码大量重复</li><li><strong>类型不安全</strong>：SQL 字符串拼错一个字母，运行时才报错</li><li><strong>数据库迁移麻烦</strong>：改表结构要手动维护 SQL 脚本</li><li><strong>代码和 SQL 分离</strong>：业务逻辑分散在代码和 SQL 文件里</li></ul><p>GORM 解决这些问题的方式很简单：<strong>用 Go 结构体定义表结构，用方法调用代替 SQL 语句</strong>。</p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装"><span>安装</span></a></h2><p>GORM 分两部分：核心库 + 数据库驱动。核心库提供 ORM 功能，驱动负责跟具体数据库通信。</p><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 核心库</span></span>
<span class="line">go get <span class="token parameter variable">-u</span> gorm.io/gorm</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 选一个驱动装上</span></span>
<span class="line">go get <span class="token parameter variable">-u</span> gorm.io/driver/mysql      <span class="token comment"># MySQL</span></span>
<span class="line">go get <span class="token parameter variable">-u</span> gorm.io/driver/postgres   <span class="token comment"># PostgreSQL</span></span>
<span class="line">go get <span class="token parameter variable">-u</span> gorm.io/driver/sqlite     <span class="token comment"># SQLite</span></span>
<span class="line">go get <span class="token parameter variable">-u</span> gorm.io/driver/sqlserver  <span class="token comment"># SQL Server</span></span>
<span class="line"></span></code></pre></div><h2 id="第一步-连接数据库" tabindex="-1"><a class="header-anchor" href="#第一步-连接数据库"><span>第一步：连接数据库</span></a></h2><p>连接数据库需要两样东西：<strong>驱动</strong> 和 <strong>连接信息（DSN）</strong>。</p><p>DSN 的格式因数据库而异，MySQL 的格式如下：</p><div class="language-text" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">用户名:密码@协议(地址:端口)/库名?参数</span>
<span class="line"></span></code></pre></div><p>来看一个完整的连接例子：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;gorm.io/driver/mysql&quot;</span></span>
<span class="line">    <span class="token string">&quot;gorm.io/gorm&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// DSN 格式：user:password@tcp(host:port)/dbname?charset=utf8mb4&amp;parseTime=True&amp;loc=Local</span></span>
<span class="line">    dsn <span class="token operator">:=</span> <span class="token string">&quot;root:123456@tcp(127.0.0.1:3306)/testdb?charset=utf8mb4&amp;parseTime=True&amp;loc=Local&quot;</span></span>
<span class="line"></span>
<span class="line">    db<span class="token punctuation">,</span> err <span class="token operator">:=</span> gorm<span class="token punctuation">.</span><span class="token function">Open</span><span class="token punctuation">(</span>mysql<span class="token punctuation">.</span><span class="token function">Open</span><span class="token punctuation">(</span>dsn<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>gorm<span class="token punctuation">.</span>Config<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;数据库连接失败: &quot;</span> <span class="token operator">+</span> err<span class="token punctuation">.</span><span class="token function">Error</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// db 就是数据库连接对象，后面所有操作都靠它</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>几个关键参数说明：</p><table><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td><code>charset=utf8mb4</code></td><td>支持 emoji 和特殊字符</td></tr><tr><td><code>parseTime=True</code></td><td>把数据库的 datetime/timestamp 自动转成 Go 的 <code>time.Time</code></td></tr><tr><td><code>loc=Local</code></td><td>使用本地时区</td></tr></tbody></table><h3 id="连接池配置" tabindex="-1"><a class="header-anchor" href="#连接池配置"><span>连接池配置</span></a></h3><p>GORM 底层用的是 Go 标准库的 <code>database/sql</code>，可以配置连接池：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">sqlDB<span class="token punctuation">,</span> err <span class="token operator">:=</span> db<span class="token punctuation">.</span><span class="token function">DB</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 最大空闲连接数</span></span>
<span class="line">sqlDB<span class="token punctuation">.</span><span class="token function">SetMaxIdleConns</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// 最大打开连接数</span></span>
<span class="line">sqlDB<span class="token punctuation">.</span><span class="token function">SetMaxOpenConns</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// 连接最大存活时间</span></span>
<span class="line">sqlDB<span class="token punctuation">.</span><span class="token function">SetConnMaxLifetime</span><span class="token punctuation">(</span>time<span class="token punctuation">.</span>Hour<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h2 id="第二步-定义模型" tabindex="-1"><a class="header-anchor" href="#第二步-定义模型"><span>第二步：定义模型</span></a></h2><p>模型就是 Go 结构体，每个字段对应数据库表的一列。</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> User <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID        <span class="token builtin">uint</span>           <span class="token string">\`gorm:&quot;primarykey&quot;\`</span></span>
<span class="line">    Name      <span class="token builtin">string</span>         <span class="token string">\`gorm:&quot;size:100;not null&quot;\`</span></span>
<span class="line">    Email     <span class="token builtin">string</span>         <span class="token string">\`gorm:&quot;uniqueIndex;size:255&quot;\`</span></span>
<span class="line">    Age       <span class="token builtin">int</span></span>
<span class="line">    CreatedAt time<span class="token punctuation">.</span>Time</span>
<span class="line">    UpdatedAt time<span class="token punctuation">.</span>Time</span>
<span class="line">    DeletedAt gorm<span class="token punctuation">.</span>DeletedAt <span class="token string">\`gorm:&quot;index&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre></div><h3 id="字段标签说明" tabindex="-1"><a class="header-anchor" href="#字段标签说明"><span>字段标签说明</span></a></h3><p><code>gorm:&quot;...&quot;</code> 里的内容是 GORM 的字段标签，常用的有：</p><table><thead><tr><th>标签</th><th>说明</th></tr></thead><tbody><tr><td><code>primarykey</code></td><td>主键</td></tr><tr><td><code>size:100</code></td><td>字段长度</td></tr><tr><td><code>not null</code></td><td>非空</td></tr><tr><td><code>uniqueIndex</code></td><td>唯一索引</td></tr><tr><td><code>default:18</code></td><td>默认值</td></tr><tr><td><code>column:user_name</code></td><td>自定义列名（默认用字段名的蛇形命名）</td></tr><tr><td><code>-</code></td><td>忽略该字段，不参与数据库操作</td></tr></tbody></table><h3 id="嵌入结构体" tabindex="-1"><a class="header-anchor" href="#嵌入结构体"><span>嵌入结构体</span></a></h3><p>GORM 提供了一个内嵌结构体 <code>gorm.Model</code>，包含 ID、创建时间、更新时间、删除时间四个常用字段：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> User <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model          <span class="token comment">// 嵌入：ID, CreatedAt, UpdatedAt, DeletedAt</span></span>
<span class="line">    Name  <span class="token builtin">string</span></span>
<span class="line">    Email <span class="token builtin">string</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre></div><p>等价于：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> User <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID        <span class="token builtin">uint</span>           <span class="token string">\`gorm:&quot;primarykey&quot;\`</span></span>
<span class="line">    CreatedAt time<span class="token punctuation">.</span>Time</span>
<span class="line">    UpdatedAt time<span class="token punctuation">.</span>Time</span>
<span class="line">    DeletedAt gorm<span class="token punctuation">.</span>DeletedAt <span class="token string">\`gorm:&quot;index&quot;\`</span></span>
<span class="line">    Name      <span class="token builtin">string</span></span>
<span class="line">    Email     <span class="token builtin">string</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre></div><h2 id="第三步-自动迁移" tabindex="-1"><a class="header-anchor" href="#第三步-自动迁移"><span>第三步：自动迁移</span></a></h2><p>模型定义好了，怎么让数据库里真的有这张表？GORM 的 <code>AutoMigrate</code> 可以自动创建或更新表结构：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">db<span class="token punctuation">.</span><span class="token function">AutoMigrate</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>User<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// 可以同时迁移多个模型</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">AutoMigrate</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>User<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>Order<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>Product<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><p><strong>自动迁移只会新增列和索引，不会删除已有的列</strong>，所以开发阶段可以放心用。生产环境建议用专门的迁移工具。</p><h2 id="第四步-增删改查-crud" tabindex="-1"><a class="header-anchor" href="#第四步-增删改查-crud"><span>第四步：增删改查（CRUD）</span></a></h2><h3 id="创建数据" tabindex="-1"><a class="header-anchor" href="#创建数据"><span>创建数据</span></a></h3><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// 创建单条</span></span>
<span class="line">user <span class="token operator">:=</span> User<span class="token punctuation">{</span>Name<span class="token punctuation">:</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">,</span> Email<span class="token punctuation">:</span> <span class="token string">&quot;zhangsan@example.com&quot;</span><span class="token punctuation">,</span> Age<span class="token punctuation">:</span> <span class="token number">25</span><span class="token punctuation">}</span></span>
<span class="line">result <span class="token operator">:=</span> db<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>user<span class="token punctuation">.</span>ID<span class="token punctuation">)</span>          <span class="token comment">// 创建后 ID 会被回填</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>result<span class="token punctuation">.</span>Error<span class="token punctuation">)</span>     <span class="token comment">// 错误信息</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>result<span class="token punctuation">.</span>RowsAffected<span class="token punctuation">)</span> <span class="token comment">// 影响的行数</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 批量创建</span></span>
<span class="line">users <span class="token operator">:=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>User<span class="token punctuation">{</span></span>
<span class="line">    <span class="token punctuation">{</span>Name<span class="token punctuation">:</span> <span class="token string">&quot;李四&quot;</span><span class="token punctuation">,</span> Email<span class="token punctuation">:</span> <span class="token string">&quot;lisi@example.com&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">{</span>Name<span class="token punctuation">:</span> <span class="token string">&quot;王五&quot;</span><span class="token punctuation">,</span> Email<span class="token punctuation">:</span> <span class="token string">&quot;wangwu@example.com&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h3 id="查询数据" tabindex="-1"><a class="header-anchor" href="#查询数据"><span>查询数据</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// 查询单条记录</span></span>
<span class="line"><span class="token keyword">var</span> user User</span>
<span class="line"></span>
<span class="line"><span class="token comment">// 按主键查找</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 按条件查找</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">,</span> <span class="token string">&quot;name = ?&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 查询不存在时，First 返回 gorm.ErrRecordNotFound</span></span>
<span class="line">result <span class="token operator">:=</span> db<span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">,</span> <span class="token number">999</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> errors<span class="token punctuation">.</span><span class="token function">Is</span><span class="token punctuation">(</span>result<span class="token punctuation">.</span>Error<span class="token punctuation">,</span> gorm<span class="token punctuation">.</span>ErrRecordNotFound<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;记录不存在&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 查询多条记录</span></span>
<span class="line"><span class="token keyword">var</span> users <span class="token punctuation">[</span><span class="token punctuation">]</span>User</span>
<span class="line"></span>
<span class="line"><span class="token comment">// 条件查询</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;age &gt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// IN 查询</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;name IN ?&quot;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">{</span><span class="token string">&quot;张三&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;李四&quot;</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// LIKE 查询</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;name LIKE ?&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;%张%&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 只查特定字段</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Select</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;email&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 排序</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Order</span><span class="token punctuation">(</span><span class="token string">&quot;age DESC&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 限制和偏移（分页）</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Limit</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Offset</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="更新数据" tabindex="-1"><a class="header-anchor" href="#更新数据"><span>更新数据</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// 先查询再更新</span></span>
<span class="line"><span class="token keyword">var</span> user User</span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 更新单个字段</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Model</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Update</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;张三（改）&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 更新多个字段</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Model</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Updates</span><span class="token punctuation">(</span>User<span class="token punctuation">{</span>Name<span class="token punctuation">:</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">,</span> Age<span class="token punctuation">:</span> <span class="token number">26</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// 注意：Updates 用结构体时，零值字段不会被更新</span></span>
<span class="line"><span class="token comment">// 如果想更新零值，用 map</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Model</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Updates</span><span class="token punctuation">(</span><span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token keyword">interface</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">{</span></span>
<span class="line">    <span class="token string">&quot;name&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;age&quot;</span><span class="token punctuation">:</span>  <span class="token number">0</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 条件更新（不先查询）</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Model</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>User<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;age &lt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Update</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;未成年人&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="删除数据" tabindex="-1"><a class="header-anchor" href="#删除数据"><span>删除数据</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// 先查询再删除</span></span>
<span class="line"><span class="token keyword">var</span> user User</span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Delete</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 条件删除</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;age &lt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Delete</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>User<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 如果模型包含 DeletedAt 字段，Delete 执行的是软删除</span></span>
<span class="line"><span class="token comment">// 软删除的记录不会真的消失，查询时默认也查不到它们</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 要查包含软删除的记录，用 Unscoped</span></span>
<span class="line"><span class="token keyword">var</span> users <span class="token punctuation">[</span><span class="token punctuation">]</span>User</span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Unscoped</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;name = ?&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 永久删除（物理删除）</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Unscoped</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Delete</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="第五步-高级查询" tabindex="-1"><a class="header-anchor" href="#第五步-高级查询"><span>第五步：高级查询</span></a></h2><h3 id="链式操作" tabindex="-1"><a class="header-anchor" href="#链式操作"><span>链式操作</span></a></h3><p>GORM 的方法可以链式调用，直观地拼出复杂的查询：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">db<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;age &gt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;name LIKE ?&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;%张%&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Order</span><span class="token punctuation">(</span><span class="token string">&quot;age DESC&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Limit</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Offset</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h3 id="scopes-查询范围" tabindex="-1"><a class="header-anchor" href="#scopes-查询范围"><span>Scopes（查询范围）</span></a></h3><p>对于经常重复的查询条件，可以封装成 Scopes：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// 定义一个查询范围</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">AdultUsers</span><span class="token punctuation">(</span>db <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> db<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span><span class="token string">&quot;age &gt;= ?&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">OrderByAgeDesc</span><span class="token punctuation">(</span>db <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> db<span class="token punctuation">.</span><span class="token function">Order</span><span class="token punctuation">(</span><span class="token string">&quot;age DESC&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 使用</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Scopes</span><span class="token punctuation">(</span>AdultUsers<span class="token punctuation">,</span> OrderByAgeDesc<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h3 id="分页查询的通用写法" tabindex="-1"><a class="header-anchor" href="#分页查询的通用写法"><span>分页查询的通用写法</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token function">Paginate</span><span class="token punctuation">(</span>page<span class="token punctuation">,</span> pageSize <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token keyword">func</span><span class="token punctuation">(</span>db <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token keyword">func</span><span class="token punctuation">(</span>db <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">if</span> page <span class="token operator">&lt;=</span> <span class="token number">0</span> <span class="token punctuation">{</span></span>
<span class="line">            page <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        <span class="token keyword">if</span> pageSize <span class="token operator">&lt;=</span> <span class="token number">0</span> <span class="token operator">||</span> pageSize <span class="token operator">&gt;</span> <span class="token number">100</span> <span class="token punctuation">{</span></span>
<span class="line">            pageSize <span class="token operator">=</span> <span class="token number">20</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        offset <span class="token operator">:=</span> <span class="token punctuation">(</span>page <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">*</span> pageSize</span>
<span class="line">        <span class="token keyword">return</span> db<span class="token punctuation">.</span><span class="token function">Offset</span><span class="token punctuation">(</span>offset<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Limit</span><span class="token punctuation">(</span>pageSize<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 使用</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Scopes</span><span class="token punctuation">(</span><span class="token function">Paginate</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="分组与聚合" tabindex="-1"><a class="header-anchor" href="#分组与聚合"><span>分组与聚合</span></a></h3><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> Result <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Name  <span class="token builtin">string</span></span>
<span class="line">    Total <span class="token builtin">int</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">var</span> results <span class="token punctuation">[</span><span class="token punctuation">]</span>Result</span>
<span class="line"></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Model</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>User<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Select</span><span class="token punctuation">(</span><span class="token string">&quot;name, count(*) as total&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Group</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Having</span><span class="token punctuation">(</span><span class="token string">&quot;count(*) &gt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Scan</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>results<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h3 id="原生-sql" tabindex="-1"><a class="header-anchor" href="#原生-sql"><span>原生 SQL</span></a></h3><p>当 ORM 的表达力不够时，可以直接写 SQL：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> Result <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Name  <span class="token builtin">string</span></span>
<span class="line">    Email <span class="token builtin">string</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">var</span> results <span class="token punctuation">[</span><span class="token punctuation">]</span>Result</span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Raw</span><span class="token punctuation">(</span><span class="token string">&quot;SELECT name, email FROM users WHERE age &gt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Scan</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>results<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h2 id="第六步-模型关联" tabindex="-1"><a class="header-anchor" href="#第六步-模型关联"><span>第六步：模型关联</span></a></h2><p>GORM 支持四种常见的关联关系。</p><h3 id="一对一-hasone" tabindex="-1"><a class="header-anchor" href="#一对一-hasone"><span>一对一（HasOne）</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> User <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model</span>
<span class="line">    Name    <span class="token builtin">string</span></span>
<span class="line">    Profile Profile <span class="token comment">// 一个用户有一个 Profile</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> Profile <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model</span>
<span class="line">    UserID <span class="token builtin">uint</span>   <span class="token comment">// 外键（GORM 自动识别）</span></span>
<span class="line">    Bio    <span class="token builtin">string</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 创建时关联</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>User<span class="token punctuation">{</span></span>
<span class="line">    Name<span class="token punctuation">:</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    Profile<span class="token punctuation">:</span> Profile<span class="token punctuation">{</span>Bio<span class="token punctuation">:</span> <span class="token string">&quot;Hello&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 查询时预加载</span></span>
<span class="line"><span class="token keyword">var</span> user User</span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span><span class="token string">&quot;Profile&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="一对多-hasmany" tabindex="-1"><a class="header-anchor" href="#一对多-hasmany"><span>一对多（HasMany）</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> User <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model</span>
<span class="line">    Name   <span class="token builtin">string</span></span>
<span class="line">    Orders <span class="token punctuation">[</span><span class="token punctuation">]</span>Order <span class="token comment">// 一个用户有多个订单</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> Order <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model</span>
<span class="line">    UserID <span class="token builtin">uint</span>    <span class="token comment">// 外键</span></span>
<span class="line">    Amount <span class="token builtin">float64</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 查询时预加载</span></span>
<span class="line"><span class="token keyword">var</span> users <span class="token punctuation">[</span><span class="token punctuation">]</span>User</span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span><span class="token string">&quot;Orders&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 带条件的预加载</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span><span class="token string">&quot;Orders&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;amount &gt; ?&quot;</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="多对多-manytomany" tabindex="-1"><a class="header-anchor" href="#多对多-manytomany"><span>多对多（ManyToMany）</span></a></h3><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> User <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model</span>
<span class="line">    Name    <span class="token builtin">string</span></span>
<span class="line">    Languages <span class="token punctuation">[</span><span class="token punctuation">]</span>Language <span class="token string">\`gorm:&quot;many2many:user_languages;&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> Language <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    gorm<span class="token punctuation">.</span>Model</span>
<span class="line">    Name  <span class="token builtin">string</span></span>
<span class="line">    Users <span class="token punctuation">[</span><span class="token punctuation">]</span>User <span class="token string">\`gorm:&quot;many2many:user_languages;&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// GORM 会自动创建中间表 user_languages</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span><span class="token string">&quot;Languages&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h3 id="预加载的更多用法" tabindex="-1"><a class="header-anchor" href="#预加载的更多用法"><span>预加载的更多用法</span></a></h3><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// 嵌套预加载</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span><span class="token string">&quot;Orders.Items&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span><span class="token string">&quot;Profile&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">First</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 预加载全部关联</span></span>
<span class="line">db<span class="token punctuation">.</span><span class="token function">Preload</span><span class="token punctuation">(</span>clause<span class="token punctuation">.</span>Associations<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>users<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre></div><h2 id="第七步-事务" tabindex="-1"><a class="header-anchor" href="#第七步-事务"><span>第七步：事务</span></a></h2><p>事务保证一组数据库操作要么全部成功，要么全部回滚。</p><h3 id="自动事务-推荐" tabindex="-1"><a class="header-anchor" href="#自动事务-推荐"><span>自动事务（推荐）</span></a></h3><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">err <span class="token operator">:=</span> db<span class="token punctuation">.</span><span class="token function">Transaction</span><span class="token punctuation">(</span><span class="token keyword">func</span><span class="token punctuation">(</span>tx <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 在事务中执行操作</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">:=</span> tx<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span><span class="token punctuation">.</span>Error<span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> err <span class="token comment">// 返回错误 → 自动回滚</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">:=</span> tx<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>order<span class="token punctuation">)</span><span class="token punctuation">.</span>Error<span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> err <span class="token comment">// 同上</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span> <span class="token comment">// 返回 nil → 自动提交</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;事务失败:&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre></div><h3 id="手动事务" tabindex="-1"><a class="header-anchor" href="#手动事务"><span>手动事务</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">tx <span class="token operator">:=</span> db<span class="token punctuation">.</span><span class="token function">Begin</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">user <span class="token operator">:=</span> User<span class="token punctuation">{</span>Name<span class="token punctuation">:</span> <span class="token string">&quot;张三&quot;</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">:=</span> tx<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>user<span class="token punctuation">)</span><span class="token punctuation">.</span>Error<span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    tx<span class="token punctuation">.</span><span class="token function">Rollback</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">order <span class="token operator">:=</span> Order<span class="token punctuation">{</span>UserID<span class="token punctuation">:</span> user<span class="token punctuation">.</span>ID<span class="token punctuation">,</span> Amount<span class="token punctuation">:</span> <span class="token number">99.9</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">:=</span> tx<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>order<span class="token punctuation">)</span><span class="token punctuation">.</span>Error<span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    tx<span class="token punctuation">.</span><span class="token function">Rollback</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">tx<span class="token punctuation">.</span><span class="token function">Commit</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="第八步-钩子-hooks" tabindex="-1"><a class="header-anchor" href="#第八步-钩子-hooks"><span>第八步：钩子（Hooks）</span></a></h2><p>钩子是在数据库操作前后自动执行的方法。GORM 支持以下钩子：</p><table><thead><tr><th>操作</th><th>前</th><th>后</th></tr></thead><tbody><tr><td>创建</td><td><code>BeforeCreate</code></td><td><code>AfterCreate</code></td></tr><tr><td>查询</td><td></td><td><code>AfterFind</code></td></tr><tr><td>更新</td><td><code>BeforeUpdate</code></td><td><code>AfterUpdate</code></td></tr><tr><td>删除</td><td><code>BeforeDelete</code></td><td><code>AfterDelete</code></td></tr><tr><td>保存</td><td><code>BeforeSave</code></td><td><code>AfterSave</code></td></tr></tbody></table><p>常见用法——密码加密：</p><div class="language-go" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>u <span class="token operator">*</span>User<span class="token punctuation">)</span> <span class="token function">BeforeCreate</span><span class="token punctuation">(</span>tx <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token punctuation">(</span>err <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 密码自动加密</span></span>
<span class="line">    hashed<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> bcrypt<span class="token punctuation">.</span><span class="token function">GenerateFromPassword</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>u<span class="token punctuation">.</span>Password<span class="token punctuation">)</span><span class="token punctuation">,</span> bcrypt<span class="token punctuation">.</span>DefaultCost<span class="token punctuation">)</span></span>
<span class="line">    u<span class="token punctuation">.</span>Password <span class="token operator">=</span> <span class="token function">string</span><span class="token punctuation">(</span>hashed<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>u <span class="token operator">*</span>User<span class="token punctuation">)</span> <span class="token function">BeforeUpdate</span><span class="token punctuation">(</span>tx <span class="token operator">*</span>gorm<span class="token punctuation">.</span>DB<span class="token punctuation">)</span> <span class="token punctuation">(</span>err <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">if</span> u<span class="token punctuation">.</span>Password <span class="token operator">!=</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">{</span></span>
<span class="line">        hashed<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> bcrypt<span class="token punctuation">.</span><span class="token function">GenerateFromPassword</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>u<span class="token punctuation">.</span>Password<span class="token punctuation">)</span><span class="token punctuation">,</span> bcrypt<span class="token punctuation">.</span>DefaultCost<span class="token punctuation">)</span></span>
<span class="line">        u<span class="token punctuation">.</span>Password <span class="token operator">=</span> <span class="token function">string</span><span class="token punctuation">(</span>hashed<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre></div><hr>`,79),i(`p`,null,[l[2]||=e(`掌握了上面这些内容，日常开发中的数据库操作基本够用了。更多进阶技巧可以参考 `,-1),a(h,{to:`/go-tutor/framework/gorm/gorm-tips.html`},{default:r(()=>[...l[0]||=[e(`GORM 技巧`,-1)]]),_:1}),l[3]||=e(` 和 `,-1),a(h,{to:`/go-tutor/framework/gorm/go-id.html`},{default:r(()=>[...l[1]||=[e(`ID 生成策略`,-1)]]),_:1}),l[4]||=e(`。`,-1)])])}var f=c(u,[[`render`,d]]);export{l as _pageData,f as default};